const query = $json.query || {};
const user_id = query.user_id || null;
const year = parseInt(query.year) || new Date().getFullYear();
const month = parseInt(query.month) || null;

if (!user_id) {
  throw new Error('user_id is required');
}

return [{
  json: {
    user_id,
    year,
    month
  }
}];

const params = $json;
let url = `{{$env.SUPABASE_URL}}/rest/v1/transactions?user_id=eq.${params.user_id}&select=type,total,transaction_date,category`;

if (params.month) {
  const startDate = `${params.year}-${String(params.month).padStart(2, '0')}-01`;
  const endDate = new Date(params.year, params.month, 0);
  const endDateStr = `${params.year}-${String(params.month).padStart(2, '0')}-${String(endDate.getDate()).padStart(2, '0')}`;
  url += `&transaction_date=gte.${startDate}&transaction_date=lte.${endDateStr}`;
} else {
  url += `&transaction_date=gte.${params.year}-01-01&transaction_date=lte.${params.year}-12-31`;
}

return [{
  json: {
    url,
    year: params.year,
    month: params.month,
    user_id: params.user_id
  }
}];

const transactions = Array.isArray($json) ? $json : [$json];
const params = $('Build Report URL').first().json;

// Group by month
const monthlyData = {};
let totalExpense = 0;
let totalMoneySaving = 0;
const categoryBreakdown = {};

transactions.forEach(tx => {
  const date = new Date(tx.transaction_date);
  const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;

  if (!monthlyData[monthKey]) {
    monthlyData[monthKey] = {
      month: monthKey,
      expense: 0,
      money_saving: 0,
      total: 0,
      count: 0
    };
  }

  const amount = parseFloat(tx.total) || 0;

  if (tx.type === 'expense') {
    monthlyData[monthKey].expense += amount;
    totalExpense += amount;
  } else if (tx.type === 'money_saving') {
    monthlyData[monthKey].money_saving += amount;
    totalMoneySaving += amount;
  }

  monthlyData[monthKey].total += amount;
  monthlyData[monthKey].count += 1;

  // Category breakdown
  const category = tx.category || 'Uncategorized';
  if (!categoryBreakdown[category]) {
    categoryBreakdown[category] = {
      category,
      total: 0,
      count: 0
    };
  }
  categoryBreakdown[category].total += amount;
  categoryBreakdown[category].count += 1;
});

const monthlyReport = Object.values(monthlyData).sort((a, b) => a.month.localeCompare(b.month));
const categoryReport = Object.values(categoryBreakdown).sort((a, b) => b.total - a.total);

return [{
  json: {
    success: true,
    user_id: params.user_id,
    year: params.year,
    month: params.month,
    summary: {
      total_expense: totalExpense,
      total_money_saving: totalMoneySaving,
      total_transactions: transactions.length
    },
    monthly_report: monthlyReport,
    category_breakdown: categoryReport
  }
}];
